class Solution:
    def solveSudoku(self, board: List[List[str]]) -> None:
        def ok(r,c,d):
            for i in range(9):
                if board[r][i]==d or board[i][c]==d: return False
            br,bc=r//3*3,c//3*3
            for i in range(3):
                for j in range(3):
                    if board[br+i][bc+j]==d: return False
            return True
        def dfs():
            for r in range(9):
                for c in range(9):
                    if board[r][c] != '.': continue
                    for d in '123456789':
                        if ok(r,c,d):
                            board[r][c]=d
                            if dfs(): return True
                            board[r][c]='.'
                    return False
            return True
        dfs()

